import './FAB.scss';

import React, { forwardRef } from 'react';

import { classNames } from '../../helpers/classnames';
import { Button } from '../Button';
import { Icon } from '../Icon';
import type { FABProps } from './FAB.types';

export const FAB = forwardRef<HTMLButtonElement, FABProps>(
	({ type = 'standard', iconName, className, children, dataTestId = 'FAB', ...props }, ref) => (
		<Button
			data-testid={dataTestId}
			{...props}
			ref={ref}
			startIcon={<Icon iconName={iconName} size="large" />}
			className={classNames('inverseTheme dsb_fab-button', `dsb_fab-button__${type}`, className)}
		>
			{type === 'extended' && children}
		</Button>
	),
);
